const feedbackRaw = $('Supabase → Recent Feedback').all().map(i => i.json);
const classified = $input.first().json.content?.[0]?.text || '[]';

let parsed = [];
try {
  const cleaned = classified.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = [{ raw: classified }];
}

const counts = { bug: 0, feature_request: 0, ux_issue: 0, praise: 0, other: 0 };
if (Array.isArray(parsed)) {
  parsed.forEach(item => {
    if (item.category && counts.hasOwnProperty(item.category)) {
      counts[item.category]++;
    } else {
      counts.other++;
    }
  });
}

return [{ json: {
  status: 'completed',
  workflow: '16_feedback_collector',
  total_feedback: feedbackRaw.length,
  classified_feedback: parsed,
  counts_by_type: counts,
  completedAt: new Date().toISOString()
} }];
